def api_request(method, path, data=None):
    url = f"{SUPABASE_URL}/rest/v1/{path}"
    headers = {
        "apikey": SERVICE_KEY,
        "Authorization": f"Bearer {SERVICE_KEY}",
        "Content-Type": "application/json",
        "Prefer": "return=minimal",
    }
    if data:
        req = urllib.request.Request(url, data=json.dumps(data).encode(), headers=headers)
    else:
        req = urllib.request.Request(url, headers=headers)
    req.method = method
    resp = urllib.request.urlopen(req)
    return resp

def main():
    # Fetch category IDs
    url = f"{SUPABASE_URL}/rest/v1/categories?select=id,slug,name"
    req = urllib.request.Request(url, headers={
        "apikey": SERVICE_KEY,
        "Authorization": f"Bearer {SERVICE_KEY}",
    })
    resp = urllib.request.urlopen(req)
    categories = {c["slug"]: c for c in json.loads(resp.read())}

    # Delete all existing FAQs
    print("🗑️  Deleting all existing FAQs...")
    api_request("DELETE", "faqs?id=neq.00000000-0000-0000-0000-000000000000")
    print("✅ Deleted all existing FAQs")

    # Insert city-agnostic FAQs
    total = 0
    for slug, faqs in CATEGORY_FAQS.items():
        cat = categories.get(slug)
        if not cat:
            print(f"  ⚠️  Category not found: {slug}")
            continue

        rows = []
        for faq in faqs:
            rows.append({
                "category_id": cat["id"],
                "city_id": None,
                "question": faq["question"],
                "answer": faq["answer"],
            })

        api_request("POST", "faqs", rows)
        print(f"  ✅ {len(rows)} FAQs for {cat['name']}")
        total += len(rows)

    print(f"\n✅ Total: {total} category-level FAQs uploaded")

if __name__ == "__main__":
    main()